solution: /**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    ListNode* removeZeroSumSublists(ListNode* head) {
        ListNode dummy(0, head);
        unordered_map<int, ListNode*> seen;
        int prefix = 0;
        ListNode* cur = &dummy;
        while (cur) {
            prefix += cur->val;
            if (seen.count(prefix)) {
                ListNode* prev = seen[prefix];
                int tmp = prefix;
                for (ListNode* p = prev->next; p != cur; p = p->next) {
                    tmp += p->val;
                    seen.erase(tmp);
                }
                prev->next = cur->next;
            } else {
                seen[prefix] = cur;
            }
            cur = cur->next;
        }
        return dummy.next;
    }
};
